     5→
     6→using Microsoft.Extensions.DependencyInjection;
     7→using Microsoft.Extensions.Logging;
     8→using System.Buffers;
     9→using System.Net;
    10→
    11→namespace BootstrapBlazor.Components;
    12→
    13→/// <summary>
    14→/// Provides a base implementation for TCP socket clients, enabling connection management, data transmission,  and
    15→/// reception over TCP sockets. This class is designed to be extended by specific implementations of  TCP socket
    16→/// clients.
    17→/// </summary>
    18→/// <remarks>The <see cref="TcpSocketClientBase"/> class offers core functionality for managing TCP socket
    19→/// connections,  including connecting to remote endpoints, sending and receiving data, and handling data packages.
    20→/// Derived classes can extend or override its behavior to implement specific client logic.  Key features include: -
    21→/// Connection management with support for timeouts and cancellation tokens. - Data transmission and reception with
    22→/// optional data package handling. - Logging capabilities for tracking events and errors. - Dependency injection
    23→/// support via <see cref="IServiceProvider"/>.  This class is abstract and cannot be instantiated directly. Use a
    24→/// derived class to implement specific  functionality.</remarks>
    25→/// <param name="options"></param>
    26→public abstract class TcpSocketClientBase(SocketClientOptions options) : ITcpSocketClient
    27→{
    28→    /// <summary>
    29→    /// Gets or sets the socket client provider used for managing socket connections.
    30→    /// </summary>
    31→    protected ISocketClientProvider? SocketClientProvider { get; set; }
    32→
    33→    /// <summary>
    34→    /// Gets or sets the logger instance used for logging messages and events.
    35→    /// </summary>
    36→    protected ILogger? Logger { get; set; }
    37→
    38→    /// <summary>
    39→    /// Gets or sets the service provider used to resolve dependencies.
    40→    /// </summary>
    41→    public IServiceProvider? ServiceProvider { get; set; }
    42→
    43→    /// <summary>
    44→    /// <inheritdoc/>
    45→    /// </summary>
    46→    public SocketClientOptions Options => options;
    47→
    48→    /// <summary>
    49→    /// <inheritdoc/>
    50→    /// </summary>
    51→    public bool IsConnected => SocketClientProvider?.IsConnected ?? false;
    52→
    53→    /// <summary>
    54→    /// <inheritdoc/>
    55→    /// </summary>
    56→    public IPEndPoint LocalEndPoint => SocketClientProvider?.LocalEndPoint ?? new IPEndPoint(IPAddress.Any, 0);
    57→
    58→    /// <summary>
    59→    /// <inheritdoc/>
    60→    /// </summary>
    61→    public Func<ReadOnlyMemory<byte>, ValueTask>? ReceivedCallBack { get; set; }
    62→
    63→    private IPEndPoint? _remoteEndPoint;
    64→    private IPEndPoint? _localEndPoint;
    65→    private CancellationTokenSource? _receiveCancellationTokenSource;
    66→    private CancellationTokenSource? _autoConnectTokenSource;
    67→
    68→    /// <summary>
    69→    /// <inheritdoc/>
    70→    /// </summary>
    71→    /// <param name="endPoint"></param>
    72→    /// <param name="token"></param>
    73→    /// <returns></returns>
    74→    public async ValueTask<bool> ConnectAsync(IPEndPoint endPoint, CancellationToken token = default)
    75→    {
    76→        if (IsConnected)
    77→        {
    78→            return true;
    79→        }
    80→
    81→        var ret = false;
    82→        SocketClientProvider = ServiceProvider?.GetRequiredService<ISocketClientProvider>()
    83→            ?? throw new InvalidOperationException("SocketClientProvider is not registered in the service provider.");
    84→
    85→        try
    86→        {
    87→            ret = await ConnectCoreAsync(SocketClientProvider, endPoint, token);
    88→            if (ret == false)
    89→            {
    90→                Reconnect();
    91→            }
    92→        }
    93→        catch (OperationCanceledException ex)
    94→        {
    95→            if (token.IsCancellationRequested)
    96→            {
    97→                Log(LogLevel.Warning, ex, $"TCP Socket connect operation was canceled from {LocalEndPoint} to {endPoint}");
    98→            }
    99→            else
   100→            {
   101→                Log(LogLevel.Warning, ex, $"TCP Socket connect operation timed out from {LocalEndPoint} to {endPoint}");
   102→                Reconnect();
   103→            }
   104→        }
   105→        catch (Exception ex)
   106→        {
   107→            Log(LogLevel.Error, ex, $"TCP Socket connection failed from {LocalEndPoint} to {endPoint}");
   108→            Reconnect();
   109→        }
   110→        return ret;
   111→    }
   112→
   113→    private void Reconnect()
   114→    {
   115→        if (options.IsAutoReconnect)
   116→        {
   117→            Task.Run(async () =>
   118→            {
   119→                try
   120→                {
   121→                    _autoConnectTokenSource ??= new();
   122→                    await Task.Delay(options.ReconnectInterval, _autoConnectTokenSource.Token).ConfigureAwait(false);
   123→                    HandleDisconnection();
   124→                }
   125→                catch { }
   126→            }, CancellationToken.None).ConfigureAwait(false);
   127→        }
   128→    }
   129→
   130→    private async ValueTask<bool> ConnectCoreAsync(ISocketClientProvider provider, IPEndPoint endPoint, CancellationToken token)
   131→    {
   132→        // 释放资源
   133→        await CloseAsync();
   134→
   135→        // 创建新的 TcpClient 实例
   136→        provider.LocalEndPoint = Options.LocalEndPoint;
   137→
   138→        _localEndPoint = Options.LocalEndPoint;
   139→        _remoteEndPoint = endPoint;
   140→
   141→        var connectionToken = token;
   142→        if (Options.ConnectTimeout > 0)
   143→        {
   144→            // 设置连接超时时间
   145→            var connectTokenSource = new CancellationTokenSource(options.ConnectTimeout);
   146→            connectionToken = CancellationTokenSource.CreateLinkedTokenSource(token, connectTokenSource.Token).Token;
   147→        }
   148→        var ret = await provider.ConnectAsync(endPoint, connectionToken);
   149→
   150→        if (ret)
   151→        {
   152→            _localEndPoint = provider.LocalEndPoint;
   153→
   154→            if (options.IsAutoReceive)
   155→            {
   156→                _ = Task.Run(AutoReceiveAsync, CancellationToken.None).ConfigureAwait(false);
   157→            }
   158→        }
   159→        return ret;
   160→    }
   161→
   162→    private void HandleDisconnection()
   163→    {
   164→        if (options.IsAutoReconnect && _remoteEndPoint != null)
   165→        {
   166→            _autoConnectTokenSource ??= new();
   167→            _ = Task.Run(() => ConnectAsync(_remoteEndPoint, _autoConnectTokenSource.Token)).ConfigureAwait(false);
   168→        }
   169→    }
   170→
   171→    /// <summary>
   172→    /// <inheritdoc/>
   173→    /// </summary>
   174→    /// <param name="data"></param>
   175→    /// <param name="token"></param>
   176→    /// <returns></returns>
   177→    public virtual async ValueTask<bool> SendAsync(ReadOnlyMemory<byte> data, CancellationToken token = default)
   178→    {
   179→        if (SocketClientProvider is not { IsConnected: true })
   180→        {
   181→            throw new InvalidOperationException($"TCP Socket is not connected {LocalEndPoint}");
   182→        }
   183→
   184→        var ret = false;
   185→        try
   186→        {
   187→            var sendToken = token;
   188→            if (options.SendTimeout > 0)
   189→            {
   190→                // 设置发送超时时间
   191→                var sendTokenSource = new CancellationTokenSource(options.SendTimeout);
   192→                sendToken = CancellationTokenSource.CreateLinkedTokenSource(token, sendTokenSource.Token).Token;
   193→            }
   194→            ret = await SocketClientProvider.SendAsync(data, sendToken);
   195→            if (ret == false)
   196→            {
   197→                HandleDisconnection();
   198→            }
   199→        }
   200→        catch (OperationCanceledException ex)
   201→        {
   202→            if (token.IsCancellationRequested)
   203→            {
   204→                Log(LogLevel.Warning, ex, $"TCP Socket send operation was canceled from {_localEndPoint} to {_remoteEndPoint}");
   205→            }
   206→            else
   207→            {
   208→                Log(LogLevel.Warning, ex, $"TCP Socket send operation timed out from {_localEndPoint} to {_remoteEndPoint}");
   209→            }
   210→        }
   211→        catch (Exception ex)
   212→        {
   213→            Log(LogLevel.Error, ex, $"TCP Socket send failed from {_localEndPoint} to {_remoteEndPoint}");
   214→
   215→            HandleDisconnection();
   216→        }
   217→
   218→        if (options.EnableLog)
   219→        {
   220→            Log(LogLevel.Information, null, $"Sending data from {_localEndPoint} to {_remoteEndPoint}, Data Length: {data.Length} Data Content: {BitConverter.ToString(data.ToArray())} Result: {ret}");
   221→        }
   222→        return ret;
   223→    }
   224→
   225→    /// <summary>
   226→    /// <inheritdoc/>
   227→    /// </summary>
   228→    /// <param name="token"></param>
   229→    /// <returns></returns>
   230→    public virtual async ValueTask<Memory<byte>> ReceiveAsync(CancellationToken token = default)
   231→    {
   232→        if (SocketClientProvider is not { IsConnected: true })
   233→        {
   234→            throw new InvalidOperationException($"TCP Socket is not connected {LocalEndPoint}");
   235→        }
   236→
   237→        if (options.IsAutoReceive)
   238→        {
   239→            throw new InvalidOperationException("Cannot call ReceiveAsync when IsAutoReceive is true. Use the auto-receive mechanism instead.");
   240→        }
   241→
   242→        using var block = MemoryPool<byte>.Shared.Rent(options.ReceiveBufferSize);
   243→        var buffer = block.Memory;
   244→        var len = await ReceiveCoreAsync(SocketClientProvider, buffer, token);
   245→        if (len == 0)
   246→        {
   247→            HandleDisconnection();
   248→        }
   249→        return buffer[..len];
   250→    }
   251→
   252→    private async ValueTask AutoReceiveAsync()
   253→    {
   254→        // 自动接收方法
   255→        _receiveCancellationTokenSource ??= new();
   256→        while (_receiveCancellationTokenSource is { IsCancellationRequested: false })
   257→        {
   258→            if (SocketClientProvider is not { IsConnected: true })
   259→            {
   260→                throw new InvalidOperationException($"TCP Socket is not connected {LocalEndPoint}");
   261→            }
   262→
   263→            using var block = MemoryPool<byte>.Shared.Rent(options.ReceiveBufferSize);
   264→            var buffer = block.Memory;
   265→            var len = await ReceiveCoreAsync(SocketClientProvider, buffer, _receiveCancellationTokenSource.Token);
   266→            if (len == 0)
   267→            {
   268→                // 远端关闭或者 DisposeAsync 方法被调用时退出
   269→                break;
   270→            }
   271→        }
   272→
   273→        HandleDisconnection();
   274→    }
   275→
   276→    private async ValueTask<int> ReceiveCoreAsync(ISocketClientProvider client, Memory<byte> buffer, CancellationToken token)
   277→    {
   278→        var len = 0;
   279→        try
   280→        {
   281→            var receiveToken = token;
   282→            if (options.ReceiveTimeout > 0)
   283→            {
   284→                // 设置接收超时时间
   285→                var receiveTokenSource = new CancellationTokenSource(options.ReceiveTimeout);
   286→                receiveToken = CancellationTokenSource.CreateLinkedTokenSource(receiveToken, receiveTokenSource.Token).Token;
   287→            }
   288→
   289→            len = await client.ReceiveAsync(buffer, receiveToken);
   290→            if (len == 0)
   291→            {
   292→                // 远端主机关闭链路
   293→                Log(LogLevel.Information, null, $"TCP Socket {_localEndPoint} received 0 data closed by {_remoteEndPoint}");
   294→                buffer = Memory<byte>.Empty;
   295→
   296→                HandleDisconnection();
   297→            }
   298→            else
   299→            {
   300→                buffer = buffer[..len];
   301→            }
   302→
   303→            if (ReceivedCallBack != null)
   304→            {
   305→                // 如果订阅回调则触发回调
   306→                await ReceivedCallBack(buffer);
   307→            }
   308→        }
   309→        catch (OperationCanceledException ex)
   310→        {
   311→            if (token.IsCancellationRequested)
   312→            {
   313→                Log(LogLevel.Warning, ex, $"TCP Socket receive operation canceled from {_localEndPoint} to {_remoteEndPoint}");
   314→            }
   315→            else
   316→            {
   317→                Log(LogLevel.Warning, ex, $"TCP Socket receive operation timed out from {_localEndPoint} to {_remoteEndPoint}");
   318→            }
   319→        }
   320→        catch (Exception ex)
   321→        {
   322→            Log(LogLevel.Error, ex, $"TCP Socket receive failed from {_localEndPoint} to {_remoteEndPoint}");
   323→
   324→            HandleDisconnection();
   325→        }
   326→
   327→        if (options.EnableLog)
   328→        {
   329→            Log(LogLevel.Information, null, $"Receiving data from {_localEndPoint} to {_remoteEndPoint}, Data Length: {len} Data Content: {BitConverter.ToString(buffer.ToArray())}");
   330→        }
   331→        return len;
   332→    }
   333→
   334→    /// <summary>
   335→    /// Logs a message with the specified log level, exception, and additional context.
   336→    /// </summary>
   337→    protected virtual void Log(LogLevel logLevel, Exception? ex, string? message)
   338→    {
   339→        Logger ??= ServiceProvider?.GetRequiredService<ILogger<TcpSocketClientBase>>();
   340→        Logger?.Log(logLevel, ex, "{Message}", message);
   341→    }
   342→
   343→    /// <summary>
   344→    /// <inheritdoc/>
   345→    /// </summary>
   346→    public virtual async ValueTask CloseAsync()
   347→    {
   348→        // 取消接收数据的任务
   349→        if (_receiveCancellationTokenSource != null)
   350→        {
   351→            _receiveCancellationTokenSource.Cancel();
   352→            _receiveCancellationTokenSource.Dispose();
   353→            _receiveCancellationTokenSource = null;
   354→        }
   355→        if (SocketClientProvider != null)
   356→        {
   357→            await SocketClientProvider.CloseAsync();
   358→        }
   359→    }
   360→
   361→    /// <summary>
   362→    /// Releases the resources used by the current instance of the class.
   363→    /// </summary>
   364→    /// <remarks>This method is called to free both managed and unmanaged resources. If the <paramref
   365→    /// name="disposing"/> parameter is <see langword="true"/>, the method releases managed resources in addition to
   366→    /// unmanaged resources. Override this method in a derived class to provide custom cleanup logic.</remarks>
   367→    /// <param name="disposing"><see langword="true"/> to release both managed and unmanaged resources; <see langword="false"/> to release only
   368→    /// unmanaged resources.</param>
   369→    protected virtual async ValueTask DisposeAsync(bool disposing)
   370→    {
   371→        if (disposing)
   372→        {
   373→            // 取消重连任务
   374→            if (_autoConnectTokenSource != null)
   375→            {
   376→                _autoConnectTokenSource.Cancel();
   377→                _autoConnectTokenSource.Dispose();
   378→                _autoConnectTokenSource = null;
   379→            }
   380→
   381→            await CloseAsync();
   382→        }
   383→    }
   384→
   385→    /// <summary>
   386→    /// <inheritdoc/>
   387→    /// </summary>
   388→    public async ValueTask DisposeAsync()
   389→    {
   390→        await DisposeAsync(true);
   391→        GC.SuppressFinalize(this);
   392→    }
   393→}
   394→

