using Microsoft.Extensions.Logging;
using System.Net;
using System.Net.Sockets;

namespace UnitTest.Services;

public class TcpSocketConcurrencyTest
{
    [Fact]
    public async Task ConnectAsync_ConcurrentCalls_ShouldNotCauseConcurrencyIssues()
    {
        // Setup TCP server
        var port = 9998;
        var server = StartTcpServer(port);

        var client = CreateClient();

        // Execute multiple concurrent connect calls
        var tasks = Enumerable.Range(0, 10).Select(_ => client.ConnectAsync("localhost", port).AsTask()).ToArray();
        var results = await Task.WhenAll(tasks);

        // All tasks should complete successfully
        // Since IsConnected check happens first, subsequent calls should return true
        Assert.All(results, result => Assert.True(result));

        // Verify the client is connected
        Assert.True(client.IsConnected);

        // Cleanup
        await client.CloseAsync();
        StopTcpServer(server);
    }

    [Fact]
    public async Task ConnectAsync_MultipleConcurrentCalls_ShouldHandleRaceCondition()
    {
        // Setup TCP server with delay
        var port = 9997;
        var server = StartTcpServer(port);

        var client = CreateClient(builder =>
        {
            builder.AddTransient<ISocketClientProvider, SlowConnectSocketProvider>();
        });

        // Execute multiple concurrent connect calls before any complete
        var task1 = client.ConnectAsync("localhost", port);
        var task2 = client.ConnectAsync("localhost", port);
        var task3 = client.ConnectAsync("localhost", port);

        var results = await Task.WhenAll(task1, task2, task3);

        // All should succeed - either by actually connecting or by returning early because already connected
        Assert.All(results, result => Assert.True(result));

        // Verify the client is connected only once
        Assert.True(client.IsConnected);

        // Cleanup
        await client.CloseAsync();
        StopTcpServer(server);
    }

    [Fact]
    public async Task ConnectAsync_SimultaneousConnects_ShouldBeSynchronized()
    {
        var port = 9996;
        var server = StartTcpServer(port);

        var client = CreateClient();

        // Create a barrier to ensure all tasks start at the same time
        var barrier = new TaskCompletionSource();
        var connectCount = 0;

        var tasks = Enumerable.Range(0, 5).Select(async _ =>
        {
            await barrier.Task; // Wait for all tasks to be ready
            var result = await client.ConnectAsync("localhost", port);
            if (result)
            {
                Interlocked.Increment(ref connectCount);
            }
            return result;
        }).ToArray();

        // Release all tasks at once
        barrier.SetResult();

        var results = await Task.WhenAll(tasks);

        // All should succeed
        Assert.All(results, result => Assert.True(result));

        // Connection should happen only once
        Assert.True(client.IsConnected);

        // Cleanup
        await client.CloseAsync();
        StopTcpServer(server);
    }

    private static TcpListener StartTcpServer(int port)
    {
        var server = new TcpListener(IPAddress.Loopback, port);
        server.Start();
        Task.Run(() => AcceptClientsAsync(server));
        return server;
    }

    private static async Task AcceptClientsAsync(TcpListener server)
    {
        try
        {
            while (true)
            {
                var client = await server.AcceptTcpClientAsync();
                _ = Task.Run(async () =>
                {
                    using var stream = client.GetStream();
                    var buffer = new byte[1024];
                    while (true)
                    {
                        try
                        {
                            var len = await stream.ReadAsync(buffer);
                            if (len == 0) break;
                            await stream.WriteAsync(buffer.AsMemory(0, len));
                        }
                        catch
                        {
                            break;
                        }
                    }
                });
            }
        }
        catch { }
    }

    private static void StopTcpServer(TcpListener? server)
    {
        try
        {
            server?.Stop();
        }
        catch { }
    }

    private static ITcpSocketClient CreateClient(Action<ServiceCollection>? builder = null)
    {
        var sc = new ServiceCollection();
        sc.AddLogging(builder =>
        {
            builder.AddProvider(new MockLoggerProvider());
        });
        sc.AddBootstrapBlazorTcpSocketFactory();
        builder?.Invoke(sc);

        var provider = sc.BuildServiceProvider();
        var factory = provider.GetRequiredService<ITcpSocketFactory>();
        var client = factory.GetOrCreate("concurrency-test", op =>
        {
            op.LocalEndPoint = Utility.ConvertToIpEndPoint("localhost", 0);
            op.EnableLog = true;
        });
        return client;
    }

    class MockLoggerProvider : ILoggerProvider
    {
        public ILogger CreateLogger(string categoryName) => new MockLogger();
        public void Dispose() { }
    }

    class MockLogger : ILogger
    {
        public IDisposable? BeginScope<TState>(TState state) where TState : notnull => null;
        public bool IsEnabled(LogLevel logLevel) => true;
        public void Log<TState>(LogLevel logLevel, EventId eventId, TState state, Exception? exception, Func<TState, Exception?, string> formatter) { }
    }

    class SlowConnectSocketProvider : ISocketClientProvider
    {
        private TcpClient? _client;
        private static int _connectCallCount = 0;

        public bool IsConnected => _client?.Connected ?? false;
        public IPEndPoint LocalEndPoint { get; set; } = new IPEndPoint(IPAddress.Any, 0);

        public async ValueTask<bool> ConnectAsync(IPEndPoint endPoint, CancellationToken token = default)
        {
            Interlocked.Increment(ref _connectCallCount);

            // Simulate slow connection
            await Task.Delay(100, token);

            _client = new TcpClient();
            try
            {
                await _client.ConnectAsync(endPoint, token);
                LocalEndPoint = (IPEndPoint)_client.Client.LocalEndPoint!;
                return true;
            }
            catch
            {
                return false;
            }
        }

        public ValueTask<bool> SendAsync(ReadOnlyMemory<byte> data, CancellationToken token = default)
        {
            return ValueTask.FromResult(true);
        }

        public ValueTask<int> ReceiveAsync(Memory<byte> buffer, CancellationToken token = default)
        {
            return ValueTask.FromResult(0);
        }

        public ValueTask CloseAsync()
        {
            _client?.Close();
            _client?.Dispose();
            _client = null;
            return ValueTask.CompletedTask;
        }

        public static int GetConnectCallCount() => _connectCallCount;
    }
}

